import json,sys
p='/app/output/alloc-audit.json'
obj=json.load(open(p))
print('top keys',sorted(obj.keys()))
cases=obj.get('cases')
print('cases',len(cases))
print('order',[c.get('name') for c in cases])
need_case={'name','ok','steps','heap_sig','fl_count','fl_sig','byte_total','ledger'}
need_step={'seq','op','index','size','result_index','heap_sig','fl_count','fl_sig','byte_total'}
for c in cases:
    miss=need_case-set(c)
    if miss: print('CASE missing',c.get('name'),miss)
    steps=c.get('steps',[])
    if not steps:
        print('no steps',c.get('name')); continue
    # check step fields and monotonic seq
    for i,s in enumerate(steps):
        m=need_step-set(s)
        if m:
            print('STEP missing',c.get('name'),i,m)
            break
        if s['seq']!=i:
            print('seq mismatch',c.get('name'),i,'got',s['seq']);break
    last=steps[-1]
    for k in ['heap_sig','fl_count','fl_sig','byte_total']:
        if c.get(k)!=last.get(k):
            print('summary!=last',c.get('name'),k,c.get(k),last.get(k))
print('done')
