import json
from pathlib import Path
obj=json.load(open('/app/output/alloc-audit.json'))
for c in obj['cases']:
    lp=Path(c['ledger'])
    if not lp.exists():
        print('missing ledger',c['name'],lp); continue
    rows=[]
    for line in lp.read_text().splitlines():
        rows.append(json.loads(line))
    if len(rows)!=len(c['steps']):
        print('ledger len mismatch',c['name'],len(rows),len(c['steps']))
    # ensure required fields present in ledger rows
    need={'seq','op','index','size','result_index','heap_sig','fl_count','fl_sig','byte_total'}
    for i,r in enumerate(rows[:5]):
        pass
    for i,r in enumerate(rows):
        m=need-set(r)
        if m:
            print('ledger missing fields',c['name'],i,m);break
        if r['seq']!=i:
            print('ledger seq mismatch',c['name'],i,'got',r['seq']);break
print('ledger check done')
